class Solution:
    def canTraverseAllPairs(self, nums) -> bool:
        n = len(nums)
        if n == 1:
            return True
        from collections import defaultdict
        maxv = max(nums)
        spf = list(range(maxv + 1))
        i = 2
        while i * i <= maxv:
            if spf[i] == i:
                for j in range(i * i, maxv + 1, i):
                    if spf[j] == j:
                        spf[j] = i
            i += 1
        prime_groups = defaultdict(list)
        adj = defaultdict(set)
        for idx, v in enumerate(nums):
            x = v
            primes = set()
            while x > 1:
                p = spf[x]
                primes.add(p)
                while x % p == 0:
                    x //= p
            for p in primes:
                prime_groups[p].append(idx)
        for p, idxs in prime_groups.items():
            for k in range(1, len(idxs)):
                a, b = idxs[k - 1], idxs[k]
                adj[a].add(b)
                adj[b].add(a)
        visited = {0}
        stack = [0]
        while stack:
            u = stack.pop()
            for w in adj[u]:
                if w not in visited:
                    visited.add(w)
                    stack.append(w)
        return len(visited) == n

