class Solution:
    def canTraverseAllPairs(self, nums) -> bool:
        n = len(nums)
        if n == 1:
            return True
        maxv = max(nums)
        spf = list(range(maxv + 1))
        i = 2
        while i * i <= maxv:
            if spf[i] == i:
                for j in range(i * i, maxv + 1, i):
                    if spf[j] == j:
                        spf[j] = i
            i += 1
        parent = {}

        def find(x):
            if x not in parent:
                parent[x] = x
            root = x
            while parent[root] != root:
                root = parent[root]
            while parent[x] != root:
                parent[x], x = root, parent[x]
            return root

        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb

        for idx, v in enumerate(nums):
            if v == 1:
                find(idx)
                continue
            x = v
            while x > 1:
                p = spf[x]
                union(idx, ('p', p))
                while x % p == 0:
                    x //= p

        roots = {find(idx) for idx in range(n)}
        return len(roots) == 1

