var canTraverseAllPairs = function(nums) {
    const n = nums.length;
    if (n === 1) return true;
    const maxv = Math.max(...nums);
    const spf = new Int32Array(maxv + 1);
    for (let i = 0; i <= maxv; i++) spf[i] = i;
    for (let i = 2; i * i <= maxv; i++) {
        if (spf[i] === i) {
            for (let j = i * i; j <= maxv; j += i) {
                if (spf[j] === j) spf[j] = i;
            }
        }
    }
    const parent = new Map();
    function find(x) {
        if (!parent.has(x)) parent.set(x, x);
        let root = x;
        while (parent.get(root) !== root) root = parent.get(root);
        while (parent.get(x) !== root) {
            const next = parent.get(x);
            parent.set(x, root);
            x = next;
        }
        return root;
    }
    function union(a, b) {
        const ra = find(a);
        const rb = find(b);
        if (ra !== rb) parent.set(ra, rb);
    }
    for (let idx = 0; idx < n; idx++) {
        let v = nums[idx];
        if (v === 1) {
            find(idx);
            continue;
        }
        let x = v;
        while (x > 1) {
            const p = spf[x];
            union(idx, 'p:' + p);
            while (x % p === 0) x = Math.floor(x / p);
        }
    }
    const roots = new Set();
    for (let idx = 0; idx < n; idx++) roots.add(find(idx));
    return roots.size === 1;
};
